# TARGET_ARCH 是 make 时的参数，用于指定编译架构
# 如果没有指定TARGET_ARCH，则编译所有架构
# 当前支持：riscv64, loongarch64

# TARGET_ARCH ?= loongarch64

ifdef TARGET_ARCH
all: build-arch
else
all: riscv64-build loongarch64-build
endif

export PROJECT_ROOT := $(CURDIR)

ifdef TARGET_ARCH
ifeq ($(TARGET_ARCH), riscv64)
	include make_scripts/riscv64.mk
else ifeq ($(TARGET_ARCH), loongarch64)
	include make_scripts/loongarch64.mk
else
	$(error Unsupported TARGET_ARCH: $(TARGET_ARCH))
endif
include make_scripts/user.mk
endif

riscv64-build: 
	@echo "=========================================="
	@echo "Building for RISCV64 architecture..."
	@echo "=========================================="
	@$(MAKE) build-arch TARGET_ARCH=riscv64

loongarch64-build:
	@echo "=========================================="
	@echo "Building for LoongArch64 architecture..."
	@echo "=========================================="
	@$(MAKE) build-arch TARGET_ARCH=loongarch64

build-arch: set_env_arch
	@echo "Kernel build arguments: $(KERNEL_BUILD_ARGS)"
	@$(MAKE) setup_cargo
	@echo "Building user programs for $(TARGET_ARCH)..."
	@cd ./user && $(MAKE) build
	@echo "------------------------------------------- user programs built successfully"
	@echo "Building kernel for $(TARGET_ARCH)..."
	@cd ./os && $(MAKE) build KERNEL_OUTPUT_LOG_LEVEL=warn
	@$(MAKE) cleanup_cargo
	@echo "$(TARGET_ARCH) build completed successfully!"

set_env_arch:
ifeq ($(TARGET_ARCH), riscv64)
	$(eval include make_scripts/riscv64.mk)
	$(eval include make_scripts/user.mk)
else ifeq ($(TARGET_ARCH), loongarch64)
	$(eval include make_scripts/loongarch64.mk)
	$(eval include make_scripts/user.mk)
else
	$(error Unsupported TARGET_ARCH: $(TARGET_ARCH))
endif
	@(rustup target list | grep "${TARGET} (installed)") || rustup target add $(TARGET)
	@rustup component add rust-src
	@rustup component add llvm-tools-preview

log: 
ifdef TARGET_ARCH
	@$(MAKE) log-arch TARGET_ARCH=$(TARGET_ARCH)
else
	@echo "Usage: make log TARGET_ARCH=riscv64"
endif

riscv64-log:
	@echo "=========================================="
	@echo "Building log for RISCV64 architecture..."
	@echo "=========================================="
	@$(MAKE) log-arch TARGET_ARCH=riscv64

loongarch64-log:
	@echo "=========================================="
	@echo "Building log for LoongArch64 architecture..."
	@echo "=========================================="
	@$(MAKE) log-arch TARGET_ARCH=loongarch64

log-arch: set_env_arch
	@$(MAKE) setup_cargo
	@cd ./user && $(MAKE) build
	@cd ./os && $(MAKE) build KERNEL_OUTPUT_LOG_LEVEL=debug
	@$(MAKE) cleanup_cargo

# 注意，make run会创建一个临时软链接
run:
ifdef TARGET_ARCH
	@$(MAKE) run-arch TARGET_ARCH=$(TARGET_ARCH)
else
	@echo "Usage: make run TARGET_ARCH=riscv64"
endif

run-arch: set_env_arch
	@ln -s $(DISK_IMG) ./disk.img
	@-$(QEMU_CMD)
	@rm disk.img

clean:
	@cd ./os && $(MAKE) clean
	@cd ./user && $(MAKE) clean

objdump:
	@${OBJDUMP} -d -S $(KERNEL_ELF) > $(KERNEL_BIN).dump 2>/dev/null || true

gdbserver: all
	@echo "Starting GDB server..."
	@ln -s $(DISK_IMG) ./disk.img
	@-$(QEMU_CMD) -s -S
	@rm disk.img

gdbclient:
	@$(GDB_TOOL) $(KERNEL_ELF) \
        -ex 'target remote localhost:1234' \
		-ex 'b trap_handler' 

setup_cargo:
	-@cd ./os && mkdir -p .cargo && cp -f dotcargo/config .cargo/
	-@cd ./user && mkdir -p .cargo && cp -f dotcargo/config .cargo/

cleanup_cargo:
	-@cd ./os && rm -rf .cargo
	-@cd ./user && rm -rf .cargo

set_env:
	@(rustup target list | grep "${TARGET} (installed)") || rustup target add $(TARGET)
	@rustup component add rust-src
	@rustup component add llvm-tools-preview

.PHONY: all build-arch riscv64-build loongarch64-build set_env_arch \
        log log-arch riscv64-log loongarch64-log \
        run run-arch clean objdump gdbserver gdbclient setup_cargo cleanup_cargo set_env

