    fn put_bytes(&self, ptr: *mut u8, bytes: &[u8]) {
        let size = bytes.len();
        let mut remaining = size;
        let mut va = VirtAddr::from(ptr as usize);
        let page_table = &self.inner.get_unchecked_mut().page_table;

        while remaining != 0 {
            let offset = va.page_offset();
