pub struct Process {
    pub inner: Mutex<ProcessInner>,
    pub pid: usize,
    // pub parent: Option<Arc<Process>>,
    pub ppid: usize,
    pub meta: Mutex<ProcessMeta>,
    intr_counter: Mutex<[usize; 64]>,
}
// 我们需要向编译器保证Process含有这样的特性……这样真的好吗？
