///Processor management structure
pub struct Processor {
    ///The task currently executing on the current processor
    pub current: Option<Arc<TaskControlBlock>>,
    ///The basic control flow of each core, helping to select and switch process
    pub idle_task_cx: Option<Box<TaskContext>>,
}

///Init PROCESSORS
pub fn processors_init() {
    unsafe {
        for p in PROCESSORS.iter_mut() {
            p.idle_task_cx = Some(Box::new(TaskContext::zero_init()));
        }
    }
}

impl Processor {
    ///Create an empty Processor
    pub const fn new() -> Self {
        Self {
            current: None,
            idle_task_cx: None,
        }
    }
    ///Get mutable reference to `idle_task_cx`
    fn get_idle_task_cx_ptr(&mut self) -> *mut TaskContext {
        self.idle_task_cx.as_mut().unwrap().as_mut() as *mut _
    }
    ///Get current task in moving semanteme
    pub fn take_current(&mut self) -> Option<Arc<TaskControlBlock>> {
        self.current.take()
    }
    ///Get current task in cloning semanteme
    pub fn current(&self) -> Option<Arc<TaskControlBlock>> {
        self.current.as_ref().map(Arc::clone)
    }
}

const EMPTY_PROCESSOR: Processor = Processor::new();
/// 不需要加锁,每个核只会访问固定的Processor
pub static mut PROCESSORS: [Processor; HART_NUM] = [EMPTY_PROCESSOR; HART_NUM];

///attach to processors
fn get_proc_by_hartid(hartid: usize) -> &'static mut Processor {
    if hartid >= HART_NUM {
        panic!(
            "get_proc_by_hartid: fail because hartid={} is too large!",
            hartid
        )
    }
    unsafe { &mut PROCESSORS[hartid] }
}

///The main part of process execution and scheduling
///Loop `fetch_task` to get the process that needs to run, and switch the process through `__switch`
pub fn run_tasks() {
    loop {
        check_futex_timer();
        let processor = get_proc_by_hartid(hart_id());
        let idle_task_cx_ptr = processor.get_idle_task_cx_ptr();
        if let Some(cur_task) = take_current_task() {
            let mut cur_task_inner = cur_task.inner_lock();

            if let Some(next_task) = ready_queue::fetch_task() {
                let mut next_task_inner = next_task.inner_lock();
                let next_task_cx_ptr = &next_task_inner.task_cx as *const TaskContext;
                next_task_inner.task_status = TaskStatus::Running;
                drop(next_task_inner);
                drop(cur_task_inner);
                processor.current = Some(next_task);
                ready_queue::add_task(&cur_task);
                switch(idle_task_cx_ptr, next_task_cx_ptr);
            } else {
                cur_task_inner.task_status = TaskStatus::Running;
                let cur_task_cx_ptr = &cur_task_inner.task_cx as *const TaskContext;
                drop(cur_task_inner);
                processor.current = Some(cur_task);
                switch(idle_task_cx_ptr, cur_task_cx_ptr);
            }
        } else {
            // 第一次调度，抢占
            if let Some(task) = ready_queue::fetch_task() {
                // info!("first fetch task {}", task.pid());
                let mut task_inner = task.inner_lock();
                let next_task_cx_ptr = &task_inner.task_cx as *const TaskContext;
                task_inner.task_status = TaskStatus::Running;
                drop(task_inner);
                processor.current = Some(task);
                switch(idle_task_cx_ptr, next_task_cx_ptr);
            }
            //不切换到内核的地址空间，可能继续运行或转到别的任务
        }
    }
}
///Take the current task,leaving a None in its place
pub fn take_current_task() -> Option<Arc<TaskControlBlock>> {
    get_proc_by_hartid(hart_id()).take_current()
}
///Get running task
pub fn current_task() -> Option<Arc<TaskControlBlock>> {
    get_proc_by_hartid(hart_id()).current()
}
///Get token of the address space of current task
pub fn current_token() -> usize {
    // get_proc_by_hartid(hart_id()).token()
    get_token_from_regs()
}

///Get the mutable reference to trap context of current task
pub fn current_trap_cx() -> &'static mut TrapContext {
    current_task().unwrap().inner_lock().trap_cx()
}
///Return to idle control flow for new scheduling
pub fn schedule(switched_task_cx_ptr: *mut TaskContext) {
    let processor = get_proc_by_hartid(hart_id());
    // debug!(
    //     "[schedule] processor pid = {} , tid = {}",
    //     processor.current().unwrap().pid(),
    //     processor.current().unwrap().tid()
    // );
    let idle_task_cx_ptr = processor.get_idle_task_cx_ptr();

    switch(switched_task_cx_ptr, idle_task_cx_ptr);
}

pub fn abandon(tid: usize) {
    let processor = get_proc_by_hartid(hart_id());

    let idle_task_cx_ptr = processor.get_idle_task_cx_ptr();
    unsafe {
        __abandon(tid, idle_task_cx_ptr);
    }
}

//!Implementation of [`TaskManager`]
use super::{current_task, TaskControlBlock, TaskStatus, INITPROC};
use alloc::collections::{BTreeMap, VecDeque};
use alloc::sync::{Arc, Weak};
use alloc::vec::Vec;
use hashbrown::HashSet;
use log::debug;
use spin::{Lazy, Mutex};

pub mod ready_queue {
    use log::warn;

    use super::*;
    /// 就绪队列，存储TCB的Arc
    static READY_QUEUE: Lazy<Mutex<VecDeque<Weak<TaskControlBlock>>>> =
        Lazy::new(|| Mutex::new(VecDeque::new()));

    // 一个HashMap，用于表示一个tid是否存于TASK_MANAGER中
    // static IN_QUEUE: Lazy<Mutex<HashSet<usize>>> = Lazy::new(|| Mutex::new(HashSet::new()));
    // 算了我们不要它了

    fn task_in_queue(
        queue_guard: &spin::MutexGuard<'_, VecDeque<Weak<TaskControlBlock>>>,
        task: &Arc<TaskControlBlock>,
    ) -> bool {
        for weak_tcb in queue_guard.iter() {
            if let Some(strong_tcb) = weak_tcb.upgrade() {
                if Arc::ptr_eq(&strong_tcb, task) {
                    return true;
                }
            } else {
                warn!("task_in_queue got a None task???");
            }
        }
        return false;
    }
    /// 向就绪队列中添加
    pub fn add_task(task: &Arc<TaskControlBlock>) {
        let mut queue = READY_QUEUE.lock();
        if task_in_queue(&queue, task) {
            panic!("add task fail: task already in queue!");
            //我们的futex经得起这样的考验！
        } else {
            queue.push_back(Arc::downgrade(&task));
        }
    }

    /// 从就绪队列中取出
    pub fn fetch_task() -> Option<Arc<TaskControlBlock>> {
        loop {
            if let Some(task) = READY_QUEUE.lock().pop_front() {
                if let Some(task_arc) = task.upgrade() {
                    return Some(task_arc);
                } else {
                    warn!("fetch task got a None task???");
                    continue;
                }
            } else {
                return None;
            }
        }
    }
    /// 取就绪队列长度
    pub fn ready_procs_num() -> usize {
        READY_QUEUE.lock().len()
    }
}

pub fn wakeup_futex_task(task: Arc<TaskControlBlock>) {
    let mut task_inner = task.inner_lock();
    task_inner.task_status = TaskStatus::Ready;
    task_inner.futex_key = 0;
    task_inner.futex_pa = 0;
    drop(task_inner);
    ready_queue::add_task(&task);
}

pub mod tid_to_task {
    use super::{Arc, BTreeMap, Lazy, Mutex, TaskControlBlock, Vec};
    static TID_TO_TASK: Lazy<Mutex<BTreeMap<usize, Arc<TaskControlBlock>>>> =
        Lazy::new(|| Mutex::new(BTreeMap::new()));

    pub fn tid2task(tid: usize) -> Option<Arc<TaskControlBlock>> {
        TID_TO_TASK.lock().get(&tid).map(|x| x.clone())
    }
    /// 仅在clone时发生
    pub fn insert(tid: usize, task: Arc<TaskControlBlock>) {
        TID_TO_TASK.lock().insert(tid, task);
    }
    /// 仅在exit时发生
    pub fn remove(tid: usize) {
        let ret = TID_TO_TASK.lock().remove(&tid);
        if ret.is_none() {
            panic!("fail to remove task {}! it does not exist!", tid);
        }
    }
    /// tid_to_task模块记录的task数量
    pub fn task_num() -> usize {
        TID_TO_TASK.lock().len()
    }

    /// 构造一个vector，包括所有的TCB和他们的tid
    pub fn get_all_tasks() -> Vec<(usize, Arc<TaskControlBlock>)> {
        match TID_TO_TASK.try_lock() {
            Some(guard) => guard
                .iter()
                .map(|(&tid, task)| (tid, Arc::clone(task)))
                .collect(),
            None => {
                panic!("Fail to get all tasks!");
            }
        }
    }
}

