/// 参考 https://man7.org/linux/man-pages/man2/clone.2.html
/// void (*fn)(void* arg) 参数通过栈传递,如果stack_ptr!=0, fn=0(stack),arg=8(stack)
pub fn sys_clone(
    flags: usize,
    stack_ptr: usize,
    parent_tid_ptr: usize,
    tls_ptr: usize,
    child_tid_ptr: usize,
) -> SyscallRet {
    let flags = CloneFlags::from_bits(flags as u32).unwrap();
    debug!(
        "[sys_clone] flags {:?},stack:{:#x},parent_tid_ptr:{:#x},child_tid_ptr:{:#x},tls_ptr:{:#x}",
        flags, stack_ptr, parent_tid_ptr, child_tid_ptr, tls_ptr
    );
    // if current_task().unwrap().pid() == 4 {
    //     return Ok(current_task().unwrap().tid());
    // }

    if flags.contains(CloneFlags::CLONE_THREAD) {
        assert!(flags.contains(CloneFlags::CLONE_SIGHAND));
        assert!(flags.contains(CloneFlags::CLONE_VM));
    }
    let task = current_task().unwrap();
    let parent_inner = task.inner_lock();
    // 考虑CLONE_CHILD_CLEARTID标志位：如果为true，则当子线程结束时要释放某个特定futex
    let clear_child_tid = if flags.contains(CloneFlags::CLONE_CHILD_CLEARTID) {
        child_tid_ptr as usize
    } else {
        0
    };

    // 检查是否共享虚拟内存
    let memory_set = if flags.contains(CloneFlags::CLONE_VM) {
        task.process.inner.try_lock().unwrap().memory_set.clone()
    } else {
        Arc::new(RwLock::new(MemorySet::new(
            MemorySetInner::from_existed_user(&*task.process.inner_lock().get_locked_memory_set()),
        )))
    };
    // 检查是否共享文件系统信息
    let fs_info = if flags.contains(CloneFlags::CLONE_FS) {
        Arc::clone(&parent_inner.fs_info)
    } else {
        Arc::new(Mutex::new(FsInfo::from_another(
            &parent_inner.fs_info.lock(),
        )))
    };
    // 检查是否共享打开文件表
    let fd_table = if flags.contains(CloneFlags::CLONE_FILES) {
        Arc::clone(&parent_inner.fd_table)
    } else {
        Arc::new(FdTable::from_another(&parent_inner.fd_table))
    };
    // 检查是否共享信号处理程序表
    let sig_table = if flags.contains(CloneFlags::CLONE_SIGHAND) {
        task.process.inner.try_lock().unwrap().sig_table.clone()
    } else {
        Arc::new(Mutex::new(SigTable::from_another(
            &*task.process.inner_lock().get_locked_sigtable(),
        )))
    };

    let new_task = task.clone_process(
        flags,
        stack_ptr,
        clear_child_tid,
        &parent_inner,
        memory_set,
        fs_info,
        fd_table,
        sig_table,
    )?;
    let new_tid = new_task.tid();

    // 如果含有CLONE_SETTLS，则新线程的tp寄存器应为tls_ptr
    if flags.contains(CloneFlags::CLONE_SETTLS) {
        new_task.inner_lock().trap_cx().set_tp(tls_ptr);
    }

    // CLONE_PARENT_SETTID
    if flags.contains(CloneFlags::CLONE_PARENT_SETTID) {
        task.process
            .inner_lock()
            .get_locked_memory_set()
            .put_data(parent_tid_ptr as *mut u32, new_task.tid() as u32);
        // 子这边也要吧
        new_task
            .process
            .inner_lock()
            .get_locked_memory_set()
            .put_data(parent_tid_ptr as *mut u32, new_task.tid() as u32);
    }

    // CLONE_CHILD_SETTID
    if flags.contains(CloneFlags::CLONE_CHILD_SETTID) {
        new_task
            .process
            .inner_lock()
            .get_locked_memory_set()
            .put_data(child_tid_ptr as *mut u32, new_task.tid() as u32);
    }

    ready_queue::add_task(&new_task);
    // 将task保存于全局映射中，移交所有权

    tid_to_task::insert(new_tid, new_task);
    Ok(new_tid)
}

