fn get_vector_from_ptr(memory_set: &MemorySet, ptr: *const usize) -> Vec<String> {
    let mut ptr = ptr;
    let mut v: Vec<String> = Vec::new();

    loop {
        if ptr.is_null() {
            break;
        }
        let argv_ptr = memory_set.get_data(ptr);
        if argv_ptr == 0 {
            break;
        }
        v.push(memory_set.get_user_str(argv_ptr as *const u8));
        unsafe {
            ptr = ptr.add(1);
        }
    }

    v
}

fn push_vector_to_user_stack(
    memory_set: &MemorySet,
    sp: &mut usize,
    data: &Vec<String>,
) -> Vec<usize> {
    let mut ptrs: Vec<usize> = Vec::new();
    let mut p = *sp;
    for s in data.iter() {
        let mut bytes = s.as_bytes().to_vec();
        bytes.push(0);
        p -= bytes.len();
        memory_set.put_slice(p as *mut u8, &bytes);
        ptrs.push(p);
    }
    ptrs.push(0);
    p -= p % size_of::<usize>();
    *sp = p;
    ptrs
}

/// 参考 https://man7.org/linux/man-pages/man2/execve.2.html
pub fn sys_execve(path: *const u8, argv: *const usize, envp: *const usize) -> SyscallRet {
    debug!("[sys_execve]");
    let task = current_task().unwrap();
    let mut task_inner = task.inner_lock();

    let process = &task.process;
    let mut proc_inner_lock = process.inner_lock();
    let memory_set = proc_inner_lock.get_locked_memory_set();
    let mut path = trim_start_slash(memory_set.get_user_str(path));
    debug!("[sys_execve] path={:?}", path);
    //处理argv参数
    // let mut argv_vec = get_argv_vector(&memory_set, argv, &path);
    let mut argv = get_vector_from_ptr(&memory_set, argv);
    debug!("[sys_execve] argv={:?}", argv);

    // 这个还得留着，因为busybox真的会试图exec这样的文件
    // 以后也许可以改成检测Shebang
    if path.ends_with(".sh") {
        //.sh文件不是可执行文件，需要用busybox的sh来启动
        argv.insert(0, String::from("sh"));
        argv.insert(0, String::from("busybox"));
        path = String::from("/musl/busybox");
    }

    let mut env = get_vector_from_ptr(&memory_set, envp);
    if env.is_empty() {
        env.push("PATH=/bin:/musl/usr/bin".to_string());
        //设置系统最大负载
        env.push("ENOUGH=100000".to_string());
        // 设置HOME目录
        env.push("HOME=/home/tatlin".to_string());
        // 设置动态链接库查找点
        env.push("LD_LIBRARY_PATH=/glibc/lib:/musl/lib".to_string());
    }

    debug!("[sys_execve] env is {:?}", env);

    let mut locked_fs_info = task_inner.fs_info.lock();
    let cwd = locked_fs_info.cwd();
    let exe = locked_fs_info.exe();
    let mut abs_path = get_abs_path(&cwd, &path);
    // HXC:
    // 如果是/proc/self/exe，特殊处理
    // 这个实现有点将就，只会重构文件系统的时候再想想怎么处理吧
    if abs_path == "/proc/self/exe" {
        abs_path = exe.into();
        if argv[0] == "/proc/self/exe" {
            argv[0] = exe.into();
        }
    }
    debug!("The real abs_path is {}", abs_path);
    let app_inode = open(&abs_path, OpenFlags::O_RDONLY, NONE_MODE)?.file()?;

    let elf_data = app_inode.inode.read_all()?;
    // 检查一下是不是ELF
    // 读取前4字节
    if elf_data[0] != 0x7F
        || elf_data[1] != ('E' as u8)
        || elf_data[2] != ('L' as u8)
        || elf_data[3] != ('F' as u8)
    {
        // 这就不是ELF!
        return Err(SysErrNo::ENOEXEC); // 这个报错会告诉调用者：这不是ELF
    }
    locked_fs_info.set_exe(abs_path);
    drop(locked_fs_info);

    // task.exec(&elf_data, &argv_vec, &mut env);

    //用户栈高地址到低地址：环境变量字符串/参数字符串/aux辅助向量/环境变量地址数组/参数地址数组/参数数量
    // memory_set with elf program headers/trampoline/trap context/user stack
    drop(memory_set);
    debug!("exec: goto from_elf");
    let (memory_set, user_hp, entry_point, mut auxv) = MemorySetInner::from_elf(&elf_data);
    debug!("exec: return from from_elf");
    let memory_set = MemorySet::new(memory_set);

    task_inner.time_data.clear();

    debug!(
        "task_inner.clear_child_tid={:#x}",
        task_inner.clear_child_tid
    );

    // TODO: 此处需要clear_tid吗？
    proc_inner_lock.change_memory_set_and_sigtable(memory_set, SigTable::new());

    // 重新分配用户资源
    let memory_set = proc_inner_lock.get_locked_memory_set();
    task_inner.alloc_user_res(&memory_set);
    let fd_table = Arc::new(FdTable::from_another(&task_inner.fd_table));
    task_inner.fd_table = fd_table;
    task_inner.fd_table.close_on_exec();
    task_inner.sig_mask = SigSet::empty();
    task_inner.sig_pending = SigSet::empty();

    let mut user_sp = task_inner.user_stack_top;

    //环境变量内容入栈

    let envp = push_vector_to_user_stack(&memory_set, &mut user_sp, &env);
    let argvp = push_vector_to_user_stack(&memory_set, &mut user_sp, &argv);
    debug!("envp ={:?}", envp);
    debug!("argvp={:?}", argvp);

    //需要随便放16个字节，不知道干嘛用的。
    user_sp -= 16;
    auxv.push(Aux::new(AuxType::RANDOM, user_sp));
    for i in 0..0xf {
        memory_set.put_data((user_sp + i) as *mut u8, i as u8);
    }
    user_sp -= user_sp % 16;

    // println!("aux:");
    //将auxv放入栈中
    auxv.push(Aux::new(AuxType::EXECFN, argvp[0]));
    auxv.push(Aux::new(AuxType::NULL, 0));
    for aux in auxv.iter().rev() {
        // println!("{:?}", aux);
        user_sp -= size_of::<Aux>();
        memory_set.put_data(user_sp as *mut usize, aux.aux_type as usize);
        memory_set.put_data(
            (user_sp + size_of::<usize>()) as *mut usize,
            aux.value as usize,
        );
    }

    //将环境变量指针数组放入栈中
    // println!("env pointers:");
    user_sp -= envp.len() * size_of::<usize>();
    let envp_base = user_sp;
    memory_set.put_slice(envp_base as *mut usize, &envp);

    // println!("arg pointers:");
    user_sp -= argvp.len() * size_of::<usize>();
    let argv_base = user_sp;
    memory_set.put_slice(argv_base as *mut usize, &argvp);

    //以8字节对齐
    user_sp -= user_sp % size_of::<usize>();
    //println!("user_sp:{:#X}", user_sp);
    user_sp -= size_of::<usize>();
    memory_set.put_data(user_sp as *mut usize, argv.len());

    //将设置了O_CLOEXEC位的文件描述符关闭
    task_inner.fd_table.close_on_exec();

    let mut trap_cx = TrapContext::app_init_context(entry_point, user_sp, task.kernel_stack.top());
    trap_cx.set_a0(argv.len());
    trap_cx.set_a1(argv_base);
    trap_cx.set_a2(envp_base);
    *task_inner.trap_cx() = trap_cx;
    task_inner.user_heappoint = user_hp;
    task_inner.user_heapbottom = user_hp;
    // 不用切换页表，因为return_to_user会切换
    debug!("leave sys_execve");
    Ok(0)
}

