/// 参考 https://man7.org/linux/man-pages/man2/exit.2.html
pub fn sys_exit(exit_code: i32) -> ! {
    exit_current_and_run_next(exit_code);
    error!("[sys_exit] unreachable!();");
    unreachable!();
}

/// 参考 https://man7.org/linux/man-pages/man2/exit_group.2.html
pub fn sys_exit_group(exit_code: i32) -> SyscallRet {
    // 有的时候，一个父进程在exit的时候，它还有子进程没有exit
    // 我们的解决方案是，尽可能多地Wait4，直到没有子进程

    loop {
        let ret = sys_wait4(-1, core::ptr::null_mut(), 0);
        match ret {
            Ok(_) => {
                continue;
            }
            Err(SysErrNo::ECHILD) => {
                break;
            }
            Err(e) => {
                panic!("[sys_exit_group] unexpected SysErrNo in Wait4: {:?}", e);
            }
        }
    }
    exit_current_group_and_run_next(exit_code);
    unreachable!();
}

//! Trap handling functionality
//!
//! For rCore, we have a single trap entry point, namely `__alltraps`. At
//! initialization in [`init()`], we set the `stvec` CSR to point to it.
//!
//! All traps go through `__alltraps`, which is defined in `trap.S`. The
//! assembly language code does just enough work restore the kernel space
//! context, ensuring that Rust code safely runs, and transfers control to
//! [`trap_handler()`].
//!
//! It then calls different functionality based on what exactly the exception
//! was. For example, timer interrupts trigger task preemption, and syscalls go
//! to [`syscall()`].

