#[no_mangle]
/// handle an interrupt, exception, or system call from user space
pub fn trap_handler() {
    //记录用户空间花费CPU时间，同时准备内核空间花费CPU时间
    current_task()
        .unwrap()
        .inner_lock()
        .time_data
        .update_utime();

    let hartid = hart_id();

    set_kernel_trap_entry();
    // 记录中断号和中断次数
    let (cause, intr_number) = get_trap_cause();
    // 将中断计数器++
    // 设一个块以确保这里的对象被及时析构
    {
        let task = current_task().unwrap();
        let proc = task.get_process();
        proc.inc_intr_counter(intr_number);
    }
    let stval = get_trap_virt_addr();
    debug!(
        "111 trap_handler: scause={:?}, stval={:#x}, sepc={:#x}",
        cause,
        stval,
        current_trap_cx().get_sepc()
    );
    match cause {
        Trap::Exception(Exception::Syscall) => {
            // jump to next instruction anyway
            let mut cx = current_trap_cx();
            cx.sepc_step(4);
            let syscall_id = Syscall::from(cx.get_syscall_id());
            // get system call return value
            let result = syscall(cx.get_syscall_id(), cx.get_syscall_args());
            // cx is changed during sys_exec, so we have to call it again
            cx = current_trap_cx();
            cx.set_a0(match result {
                Ok(res) => res,
                Err(errno) => -(errno as isize) as usize,
            });
            // 打印结果
            match result {
                Ok(ret) => debug!("[syscall ret --- OK] {:?} ret = {}", syscall_id, ret),
                Err(errno) => debug!(
                    "[syscall ret --- Err] {:?} ret = {}",
                    syscall_id,
                    errno.str()
                ),
            }
        }
        Trap::Exception(Exception::StorePageFault)
        | Trap::Exception(Exception::LoadPageFault)
        | Trap::Exception(Exception::FetchInstructionPageFault) => {
            //debug!("{:?},bad addr = {:#x}", scause.cause(), stval);
            // page fault
            let mut ok;
            {
                let task = current_task().unwrap();
                let process = task.process.inner_lock();
                let memory_set = process.get_locked_memory_set();
                let is_write = cause == Trap::Exception(Exception::StorePageFault);
                // 首先检查是不是lazy导致的
                ok = memory_set.lazy_page_fault(VirtAddr::from(stval).floor(), is_write); // ok表示是否是lazy_page_fault，如果不是返回 false
                if !ok {
                    // 如果不是lazy导致的，继续检查是不是COW导致的
                    // 仅有在写的情况下，才可能出现COW PageFault
                    if is_write {
                        ok = memory_set.cow_page_fault(VirtAddr::from(stval).floor());
                    }
                }
                // drop task inner and task to avoid deadlock and exit exception
            }
            if !ok {
                warn!(
                "[kernel] hart {} {:?} in application, bad addr = {:#x}, bad instruction = {:#x}, kernel killed it.",
                hartid,
                cause,
                stval,
                current_trap_cx().get_sepc(),
            );
                //发送段错误信号
                // warn!("going to send SIGSEGV signal!");
                warn!("don't send SIGSEGV, just exit the process");
                exit_current_and_run_next(-2);
                panic!("You should not return from exit_current_and_run_next");

                let tid = current_task().unwrap().tid();
                send_signal_to_thread(tid, SigSet::SIGSEGV);
                // page fault exit code
                //exit_current_and_run_next(-2);
            }
        }
        // Trap::Exception(Exception::StoreFault)
        // | Trap::Exception(Exception::InstructionFault)
        // | Trap::Exception(Exception::LoadFault) => {
        //     warn!(
        //         "[kernel] hart {} {:?} in application, bad addr = {:#x}, bad instruction = {:#x}, kernel killed it.",
        //         hartid,
        //         scause.cause(),
        //         stval,
        //         current_trap_cx().get_sepc(),
        //     );
        //     // page fault exit code
        //     exit_current_and_run_next(-2);
        // }
        // Trap::Exception(Exception::IllegalInstruction) => {
        //     backtrace();
        //     warn!(
        //         "[kernel] [hart {}] IllegalInstruction at {:#x} in application, kernel killed it.",
        //         hartid,
        //         current_trap_cx().get_sepc(),
        //     );
        //     // illegal instruction exit code
        //     exit_current_and_run_next(-3);
        // }
        Trap::Exception(Exception::PageModifyFault) => {
            // COW可能会导向这里
            let task = current_task().unwrap();
            let process = task.process.inner_lock();
            let memory_set = process.get_locked_memory_set();
            memory_set.cow_page_fault(VirtAddr::from(stval).floor());
            tlb_page_modify_handler();
        }

        Trap::Interrupt(Interrupt::Timer) => {
            // 检查futex操作是否超时
            check_futex_timer();
            // debug!("Timer Interupt!");
            suspend_current_and_run_next();
            // set_next_trigger();
        }
        // Trap::Exception(Exception::Breakpoint) => {
        //     warn!("[kernel] Breakpoint from application");
        //     // jump to next instruction anyway
        //     let cx = current_trap_cx();
        //     cx.sepc_step(2);
        // }
        _ => {
            panic!("Unsupported trap {:?}, stval = {:#x}!", cause, stval);
        }
    }
    //检查定时器
    current_task().unwrap().check_timer();

    //记录内核空间花费CPU时间，同时准备用户空间花费CPU时间
    current_task()
        .unwrap()
        .inner_lock()
        .time_data
        .update_stime();
}

#[no_mangle]
pub fn trap_return() {
    // 检查信号，TODO：还没考虑信号先后顺序
    while let Some(signo) = check_if_any_sig_for_current_task() {
        debug!("found signo in trap_return");
        handle_signal(signo);
    }
