    debug!(
        "[sys_bind] fd={}, addr={}, len={}",
        _sockfd, _addr as usize, _addrlen
    );
    let task = current_task().unwrap();
    let process = task.process.inner_lock();
    let memory_set = process.get_locked_memory_set();
    // 取出addr的family字段
    let family: u16 = memory_set.get_data(_addr as *const u16);
    let domain = SocketDomain::from(family as u32);
    match domain {
        SocketDomain::Unix => {
            debug!("[sys_bind] is not implemented for AF_UNIX, return Ok(0)");
            return Ok(0);
        }

        SocketDomain::Inet => {
            // 取出addr的字节码
            let mut codes: [u8; 110] = [0; 110];
            for i in 0..(_addrlen as usize) {
                let code = memory_set.get_data::<u8>(unsafe { _addr.byte_add(i) });
                codes[i] = code;
            }
            debug!("code={:?}", &codes[..(_addrlen as usize)]);
            for i in 2..(_addrlen as usize) {
                if codes[i] != 0 {
                    debug!("We only support sys_bind(INET) for all-zero addr");
                }
            }
            // 反正我们已经知道addr=全0了，剩余的操作并没有必要

            Ok(0)
        }

        _ => {
            debug!(
                "[sys_bind] is not implemented for domain {:?}, return Ok(0)",
                domain
            );
            return Ok(0);
        }
    }
}

