/// input.pid<-1: 等待一个子进程，其pgid==abs(input.pid)。这里的pgid指的是进程组id
/// input.pid=-1: 等待任一一个子进程的结束。
///     这里子进程指的是调用者task所处的进程（线程组）的子进程
///     （由本线程组的task调用sys_clone但选择不把新线程置于本线程组时创建的新线程组）。
/// input.pid=0 : 等待与调用者同进程组的任一子进程的结束
/// input.pid>0 : 等待pid==input.pid的子进程的结束。从内核的视角看，这里的pid指的是线程组id(tgid)，而不是线程id(tid)。
///
/// 参考 https://man7.org/linux/man-pages/man2/wait4.2.html
pub fn sys_wait4(mut pid: isize, wstatus: *mut i32, _options: i32) -> SyscallRet {
    debug!(
        "[sys_wait4] pid={}, wstatus={:#x}, option={:#x}",
        pid, wstatus as usize, _options
    );

    let no_hang = (_options & 0x1) != 0; // 如果此项为1，当没有子进程终止时，直接返回NOCHILD
    let _untraced = (_options & 0x2) != 0; // 如果此项为1，父进程可以接收子进程的停止（stopped）​状态，而不是exit时才能接受
    let continued = (_options & 0x8) != 0; // 报告已恢复（continued）的子进程状态（需配合 WUNTRACED 使用）。

    if continued {
        panic!("We do not support WCONTINUED is wait4!");
    }

    {
        let task = current_task().unwrap();
        let process = task.process.inner_lock();
        let memory_set = process.get_locked_memory_set();
        if wstatus as usize != 0 {
            debug!(
                "[sys_wait4] before running, *wstatus={:#x}",
                memory_set.get_data(wstatus)
            );
        }
    }

    if pid < -1 {
        // 需要进程组功能
        panic!(
            "[sys_wait4] We cannot handle input.pid<-1 (input.pid={})",
            pid
        );
    }
    // 由于我们假设所有进程均属于同一个进程组，我们视pid=0为pid=-1
    if pid == 0 {
        pid = -1;
    }
    // 现在只有两种情况：pid=-1表示等待任意子进程结束，pid>0表示等待特定子进程结束

    // 新实现
    loop {
        debug!("Wait4 loop begin");
        let task = current_task().unwrap();
        let mut process_meta = task.process.meta_lock();
        // 取子进程集合

        let children: Vec<Arc<Process>> = process_meta
            .children
            .clone()
            .iter()
            .filter_map(|x| x.upgrade())
            .collect();
        debug!("Wait4 len={}", children.len());
        if children.len() == 0 {
            return Err(SysErrNo::ECHILD);
        }
        // 如果是等待特定进程，但是自己根本没有这个子进程，则退出
        if pid != -1 && children.iter().all(|proc| proc.pid != pid as usize) {
            return Err(SysErrNo::ECHILD);
        }

        let pair = children
            .iter()
            .enumerate()
            .find(|(_, p)| {
                // ++++ temporarily access child PCB exclusively
                p.all_tasks_exited() && (pid == -1 || pid as usize == p.pid)
                // ++++ release child PCB
            })
            .map(|(idx, p)| (idx, Arc::clone(p)));
        drop(children);
        if let Some((idx, child)) = pair {
            let found_pid = child.pid;
            let exit_code = child.inner_lock().get_locked_sigtable().exit_code();

            if wstatus as usize != 0x0 {
                debug!(
                    "[sys_wait4] wait pid {}: child {} exit with code {}, wstatus= {:#x}",
                    pid, found_pid, exit_code, wstatus as usize
                );
                let process = task.process.inner_lock();
                let memory_set = process.get_locked_memory_set();
                if exit_code >= 128 && exit_code <= 255 {
                    //表示由于信号而退出的
                    memory_set.put_data(wstatus, exit_code);
                } else {
                    memory_set.put_data(wstatus, exit_code << 8);
                }
            }
            // drop(child_inner);
            process_meta.children.remove(idx);
            // 从全局进程映射中移除
            // 在移除前，我们得先把手上的这个Arc给丢掉
            drop(child);
            Process::remove_from_global_map(found_pid);
            return Ok(found_pid);
        } else {
            drop(process_meta);
            drop(task);
            if no_hang {
                // 有子进程但未结束，return Ok(0)
                return Ok(0);
            } else {
                debug!("Wait4 suspend");
                suspend_current_and_run_next();
                debug!("Wait4 wakeup");
            }
        }
    }
}

use super::*;

/// 参考 https://man7.org/linux/man-pages/man2/nanosleep.2.html
pub fn sys_nanosleep(req: *const Timespec, rem: *mut Timespec) -> SyscallRet {
    let task = current_task().unwrap();
    let process = task.process.inner_lock();
    let memory_set = process.get_locked_memory_set();
    // debug!(
    //     "[sys_nanosleep] req is {:x}, rem is {:x}",
    //     req as usize, rem as usize
    // );

    let req = memory_set.get_data(req);

    // tv_nsec必须在 [0, 999999999]范围内（man2规定的）
    if req.tv_nsec >= 1_000_000_000usize {
        return Err(SysErrNo::EINVAL);
    }

    // tv_sec不能是负数（man2规定的）
    if req.tv_sec > i64::MAX as usize {
        return Err(SysErrNo::EINVAL);
    }

    let waittime = req.tv_sec * 1_000_000_000usize + req.tv_nsec;
    let begin = get_time_ms() * 1_000_000usize;
    let endtime = get_time_spec() + req;

    // debug!(
    //     "[sys_nanosleep] ready to sleep for {} sec, {} nsec",
    //     req.tv_sec, req.tv_nsec
    // );
    drop(memory_set);
    drop(process);

    while get_time_ms() * 1_000_000usize - begin < waittime {
        if let Some(_) = check_if_any_sig_for_current_task() {
            //被信号唤醒
            if rem as usize != 0 {
                let task = current_task().unwrap();
                let process = task.process.inner_lock();
                let memory_set = process.get_locked_memory_set();
                memory_set.put_data(rem, calculate_left_timespec(endtime));
            }
            return Err(SysErrNo::EINTR);
        }
        suspend_current_and_run_next();
    }
    Ok(0)
}

/// 参考 https://man7.org/linux/man-pages/man2/clock_nanosleep.2.html
pub fn sys_clock_nanosleep(
    clockid: usize,
    flags: u32,
    t: *const Timespec,
    remain: *mut Timespec,
) -> SyscallRet {
    debug!(
        "[sys_clock_nanosleep] clockid is {}, flags is {}, t is {:x}, remain is {:x}",
        clockid, flags, t as usize, remain as usize
    );

    const TIME_ABSTIME: u32 = 1;
    let task = current_task().unwrap();
    let process = task.process.inner_lock();
    let memory_set = process.get_locked_memory_set();

    const CLOCK_REALTIME: usize = 0;
    const CLOCK_MONOTONIC: usize = 1;
    const CLOCK_THREAD_CPUTIME_ID: usize = 3;
    match clockid {
        CLOCK_REALTIME | CLOCK_MONOTONIC => {}
        CLOCK_THREAD_CPUTIME_ID | _ => {
            return Err(SysErrNo::EOPNOTSUPP);
        }
    }

    if (t as isize) <= 0 || if_bad_address(t as usize) {
        return Err(SysErrNo::EFAULT);
    }

    if (remain as isize) < 0 || if_bad_address(remain as usize) {
        return Err(SysErrNo::EFAULT);
    }

    let t = memory_set.get_data(t);

    // tv_nsec必须在 [0, 999999999]范围内（man2规定的）
    if t.tv_nsec >= 1_000_000_000usize {
        return Err(SysErrNo::EINVAL);
    }

    // tv_sec不能是负数（man2规定的）
    if t.tv_sec > i64::MAX as usize {
        return Err(SysErrNo::EINVAL);
    }

    drop(memory_set);
    drop(process);

    let waittime = t.tv_sec * 1_000_000_000usize + t.tv_nsec;

    let begin = get_time_ms() * 1_000_000usize;

    // 根据不同的时钟类型处理时间基准
    let current_timespec = if clockid == CLOCK_MONOTONIC {
        // CLOCK_MONOTONIC 使用原始时间
        get_time_spec()
    } else {
        // CLOCK_REALTIME 等其他时钟使用加上 NOW_TIME_STAMP 的时间
        let mut time = get_time_spec();
        time.tv_sec += NOW_TIME_STAMP;
        time
    };

    let endtime = if flags == TIME_ABSTIME {
        //绝对时间
        t
    } else {
        //相对时间
        current_timespec + t
    };

    debug!(
        "[sys_clock_nanosleep] ready to sleep for {} sec, {} nsec, flags={}",
        t.tv_sec, t.tv_nsec, flags
    );

    if flags == TIME_ABSTIME {
        // 绝对时间模式：等待到指定的绝对时间点
        loop {
            // println!(
            //     "clockid: {}, flags: {}, endtime: {:?}",
            //     clockid, flags, endtime
            // );
            let current_time = if clockid == CLOCK_MONOTONIC {
                get_time_spec()
            } else {
                let mut time = get_time_spec();
                time.tv_sec += NOW_TIME_STAMP;
                time
            };

            // 如果当前时间已经达到或超过目标时间，退出
            if current_time >= endtime {
                break;
            }

            if let Some(_) = check_if_any_sig_for_current_task() {
                //被信号唤醒
                debug!("interupt by signal");
                if remain as usize != 0 {
                    let process = task.process.inner_lock();
                    let memory_set = process.get_locked_memory_set();
                    memory_set.put_data(remain, calculate_left_timespec(endtime));
                }
                return Err(SysErrNo::EINTR);
            }
            suspend_current_and_run_next();
        }
    } else {
        // 相对时间模式
        while get_time_ms() * 1_000_000usize - begin < waittime {
            if let Some(_) = check_if_any_sig_for_current_task() {
                //被信号唤醒
                debug!("interupt by signal");
                if remain as usize != 0 {
                    let process = task.process.inner_lock();
                    let memory_set = process.get_locked_memory_set();
                    memory_set.put_data(remain, calculate_left_timespec(endtime));
                }
                return Err(SysErrNo::EINTR);
            }
            suspend_current_and_run_next();
        }
    }
    Ok(0)
}

