fn parent_directory(path: &str) -> Option<&str> {
    // 处理 Windows 路径（`\`）和 Unix 路径（`/`）
    let trimmed_path = path.trim_end_matches('/');

    // 找到最后一个 `/` 的位置
    trimmed_path.rfind('/').map(|last_slash| {
        if last_slash == 0 {
            // 根目录（如 `/` 或 `C:/`）
            "/"
        } else {
            // 返回父目录部分
            &trimmed_path[..last_slash]
        }
    })
}

fn create_file(abs_path: &str, flags: OpenFlags, mode: u32) -> Result<FileClass, SysErrNo> {
    // 一定能找到,因为除了RootInode外都有父结点
    let parent_dir = superblock_root_inode();
    let (readable, writable) = flags.read_write();
    let inode = parent_dir.create(abs_path, flags.node_type())?;
    inode.fmode_set(mode);

    let now = get_realtime_lwext4();
    inode.set_timestamps(Some(now), Some(now), Some(now));
    // HXC: 其父文件夹的ctime,mtime也要得到更改
    // TODO: 我其实也不确定这样处理是否正当
    let parent = parent_directory(abs_path).unwrap();
    let parent_fc = parent_dir
        .find(parent, OpenFlags::O_RDWR | OpenFlags::O_DIRECTORY, 0)
        .unwrap();
    parent_fc.set_timestamps(None, Some(now), Some(now));
    drop(parent_fc);
    FsIndex::insert_inode_idx(abs_path, inode.clone());
    let osinode = OSFile::new(readable, writable, inode);
    Ok(FileClass::File(Arc::new(osinode)))
}
pub fn open(abs_path: &str, flags: OpenFlags, mode: u32) -> Result<FileClass, SysErrNo> {
    debug!("open({},{:?},{})", abs_path, flags, mode);
    // log::info!("[open] abs_path={}", abs_path);
    //判断是否是设备文件
    if find_device(abs_path) {
        let device = open_device_file(abs_path)?;
        return Ok(FileClass::Abs(device));
    }
    // 判断是不是/proc/interrupts

    if abs_path == "/proc/interrupts" {
        let task = current_task().unwrap();
        let proc = task.get_process();
        let counter_str = proc.export_intr_counter();
        let file = StringFile::new(counter_str);
        return Ok(FileClass::Abs(file));
    }

    debug!("abs_path is {}", abs_path);
    let abs_path: &str = abs_path;

    let mut inode: Option<Arc<dyn Inode>> = None;
    // 同一个路径对应一个Inode
    if FsIndex::has_inode(abs_path) {
        inode = FsIndex::find_inode_idx(abs_path);
    } else {
        let found_res = superblock_root_inode().find(abs_path, flags, 0);
        if found_res.clone().err() == Some(SysErrNo::ENOTDIR) {
            return Err(SysErrNo::ENOTDIR);
        }
        if found_res.clone().err() == Some(SysErrNo::ELOOP) {
            return Err(SysErrNo::ELOOP);
        }
        if let Ok(t) = found_res {
            FsIndex::insert_inode_idx(abs_path, t.clone());
            inode = Some(t);
        } else {
            debug!(
                "unexpected error in root_inode().find({},{:?},0):{:?}",
                abs_path,
                flags,
                found_res.clone().err().unwrap()
            );
        }
    }
    if let Some(inode) = inode {
        if flags.contains(OpenFlags::O_DIRECTORY) && inode.types() != InodeType::Dir {
            return Err(SysErrNo::ENOTDIR);
        }
        let (readable, writable) = flags.read_write();
        let osfile = OSFile::new(readable, writable, inode);
        if flags.contains(OpenFlags::O_APPEND) {
            osfile.lseek(0, SEEK_END)?;
        }
        if flags.contains(OpenFlags::O_TRUNC) {
            osfile.inode.truncate(0)?;
        }
        return Ok(FileClass::File(Arc::new(osfile)));
    }

    // 节点不存在
    if flags.contains(OpenFlags::O_CREATE) {
        return create_file(abs_path, flags, mode);
    }
    Err(SysErrNo::ENOENT)
}

//!Wrap `switch.S` as a function
use super::TaskContext;
use crate::task::tid_to_task;

extern "C" {
    /// 该汇编函数的两个参数a0, a1是两个struct TaskContext*，
    /// 该函数是将当前CPU上正在运行的控制流上下文
    /// （此处上下文指的是栈、pc（对pc的保存实际上通过保存ra实现），s系列寄存器）
    /// 保存到a0指向的位置，并从a1处获取新的上下文并运行之。
    /// 因此，该函数不会正常地返回到调用者手中
    /// 如果return 0，说明next_task_cx_ptr是从另一个switch中返回的
    /// 如果return >0，则return的是tid，需要释放tid指向的内核栈
    fn __switch(
        current_task_cx_ptr: *mut TaskContext,
        next_task_cx_ptr: *const TaskContext,
    ) -> usize;

    pub fn __abandon(tid: usize, next_task_cx_ptr: *const TaskContext) -> usize;
}

/// 对汇编函数__switch的包装
/// 会在__switch之后检查返回值，如果不为0则释放那个页
pub fn switch(current_task_cx_ptr: *mut TaskContext, next_task_cx_ptr: *const TaskContext) {
    let tid = unsafe { __switch(current_task_cx_ptr, next_task_cx_ptr) };
    if tid != 0 {
        tid_to_task::remove(tid);
    }
}

